/**
 * VansonLoader L2.3 - VLIconManager 实现
 * 统一图标管理器
 * 
 * 使用方法：
 * 1. 在下方 iconBase64Map 中填充 base64 字符串
 * 2. 代码中使用 IC(@"icon_name") 获取 UIImage
 */

#import "VLIconManager.h"

// ═══════════════════════════════════════════════════════════════════════════
// 图标 Base64 映射表
// 格式: @"icon_key" : @"base64_string"
// 请在此处填充你的 base64 图标数据 (建议尺寸: 80x80 或 120x120)
// ═══════════════════════════════════════════════════════════════════════════

static NSDictionary<NSString *, NSString *> *iconBase64Map(void) {
    static NSDictionary *map = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        map = @{
            // 主悬浮按钮图标
            @"floating_button": @"",
            
            // 内存调试窗口图标
            @"memory_debug":   @"",
            
            // 搜索结果窗口图标
            @"memory_results": @"",
            
            // 工具箱窗口图标
            @"toolbox":        @"",
            
            // 内存浏览器窗口图标
            @"memory_browser": @"",
        
            // 断点监控窗口图标
            @"watchpoint":     @"",
        };
    });
    return map;
}

// ═══════════════════════════════════════════════════════════════════════════

@implementation VLIconManager

+ (nullable UIImage *)imageForKey:(NSString *)key {
    if (!key || key.length == 0) return nil;
    
    NSString *base64 = iconBase64Map()[key];
    if (!base64 || base64.length == 0) return nil;
    
    // 跳过占位符
    if ([base64 isEqualToString:@"PLACEHOLDER"]) return nil;
    
    NSData *data = [[NSData alloc] initWithBase64EncodedString:base64 options:0];
    if (!data) return nil;
    
    return [UIImage imageWithData:data];
}

+ (NSArray<NSString *> *)allKeys {
    return iconBase64Map().allKeys;
}

@end
